import React, { useState } from "react";

function MetricsForm() {
  const [serverInfo, setServerInfo] = useState({
    host: "",
    port: 22,
    username: "",
    password: "",
    name: ""
  });

  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setServerInfo({ ...serverInfo, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setMetrics(null);

    try {
      const response = await fetch("http://localhost:8080/api/metrics/collect", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(serverInfo)
      });

      if (!response.ok) {
        throw new Error("Failed to fetch metrics");
      }

      const data = await response.json();
      setMetrics(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <form onSubmit={handleSubmit} style={{ marginBottom: "20px" }}>
        <div>
          <label>Host: </label>
          <input
            type="text"
            name="host"
            value={serverInfo.host}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label>Port: </label>
          <input
            type="number"
            name="port"
            value={serverInfo.port}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label>Username: </label>
          <input
            type="text"
            name="username"
            value={serverInfo.username}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label>Password: </label>
          <input
            type="password"
            name="password"
            value={serverInfo.password}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label>Server Name: </label>
          <input
            type="text"
            name="name"
            value={serverInfo.name}
            onChange={handleChange}
            required
          />
        </div>
        <button type="submit" style={{ marginTop: "10px" }}>
          {loading ? "Loading..." : "Get Metrics"}
        </button>
      </form>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {metrics && (
        <div>
          <h2>Metrics for {metrics.serverName}</h2>

                    <p><strong>serverName:</strong> {metrics.uptime}</p>
          <p><strong>Uptime:</strong> {metrics.uptime}</p>
          <p><strong>Uptime:</strong> {metrics.uptime}</p>
          <p><strong>CPU Usage:</strong> {metrics.cpuUsage}%</p>
          <p><strong>Memory Usage:</strong> {metrics.memoryUsage}%</p>
          <p><strong>Disk Usage:</strong> {metrics.diskUsage}%</p>
          <p><strong>Network:</strong> RX {metrics.network.bytesReceived} bytes, TX {metrics.network.bytesSent} bytes</p>
          <p><strong>Load Average:</strong> {metrics.loadAverage.join(", ")}</p>
          <p><strong>process Count:</strong> {metrics.processCount}</p>
          <p><strong>Uptime:</strong> {metrics.uptime}</p>
          <p><strong>OS Info:</strong> {metrics.osInfo}</p>
          <p><strong>Logged In Users:</strong> {metrics.loggedInUsers}</p>
          <p><strong>Swap Info:</strong> {metrics.swapInfo}</p>
          <p><strong> timestamp:</strong> {metrics.timestamp}</p>

           {/* private Long serverId;
    private String serverName;
    private String host;
    private int port;


 */}

          <h3>Top Processes</h3>
          <table border="1" cellPadding="5">
            <thead>
              <tr>
                <th>PID</th>
                <th>Command</th>
                <th>CPU %</th>
                <th>Memory %</th>
              </tr>
            </thead>
            <tbody>
              {metrics.topProcesses.map((proc, idx) => (
                <tr key={idx}>
                  <td>{proc.pid}</td>
                  <td>{proc.command}</td>
                  <td>{proc.cpu}</td>
                  <td>{proc.memory}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default MetricsForm;
